import { Injectable, signal } from '@angular/core';

export type ToastType = 'success' | 'error' | 'info';

export interface Toast {
  id: number;
  message: string;
  type: ToastType;
}

export interface ConfirmDialog {
  id: number;
  message: string;
  confirmLabel: string;
  resolve: (result: boolean) => void;
}

@Injectable({ providedIn: 'root' })
export class NotificationService {
  public toasts = signal<Toast[]>([]);
  public confirmDialog = signal<ConfirmDialog | null>(null);

  private nextId = 1;
  private toastTimers = new Map<number, ReturnType<typeof setTimeout>>();

  /** Show a dismissable toast notification */
  toast(message: string, type: ToastType = 'info', durationMs = 4000): void {
    const id = this.nextId++;
    this.toasts.update((ts) => [...ts, { id, message, type }]);
    const timer = setTimeout(() => this.dismiss(id), durationMs);
    this.toastTimers.set(id, timer);
  }

  dismiss(id: number): void {
    const timer = this.toastTimers.get(id);
    if (timer) {
      clearTimeout(timer);
      this.toastTimers.delete(id);
    }
    this.toasts.update((ts) => ts.filter((t) => t.id !== id));
  }

  /** Show a confirm dialog, returns a Promise<boolean> */
  confirm(message: string, confirmLabel = 'Confirm'): Promise<boolean> {
    return new Promise((resolve) => {
      const id = this.nextId++;
      this.confirmDialog.set({ id, message, confirmLabel, resolve });
    });
  }

  resolveConfirm(result: boolean): void {
    const dialog = this.confirmDialog();
    if (dialog) {
      dialog.resolve(result);
      this.confirmDialog.set(null);
    }
  }
}
