import { Injectable, inject, signal } from '@angular/core';
import { LlmSettingsService } from './llm-settings.service';

export type ThemeMode = 'light' | 'dark' | 'system';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private llmSettings = inject(LlmSettingsService);
  private _resolved = signal<'light' | 'dark'>('light');

  public readonly resolvedTheme = this._resolved.asReadonly();

  private mediaQuery =
    typeof window !== 'undefined'
      ? window.matchMedia('(prefers-color-scheme: dark)')
      : null;

  constructor() {
    // Apply theme on init
    this.applyTheme(this.llmSettings.getPreferences().darkMode);

    // Listen for OS-level changes (for 'system' mode)
    this.mediaQuery?.addEventListener('change', () => {
      const pref = this.llmSettings.getPreferences().darkMode;
      if (pref === 'system') this.applyTheme('system');
    });
  }

  public setTheme(mode: ThemeMode): void {
    this.llmSettings.updatePreference('darkMode', mode);
    this.applyTheme(mode);
  }

  public getTheme(): ThemeMode {
    return this.llmSettings.getPreferences().darkMode;
  }

  public toggleTheme(): void {
    const current = this.getTheme();
    // cycle: light → dark → system
    if (current === 'light') this.setTheme('dark');
    else if (current === 'dark') this.setTheme('system');
    else this.setTheme('light');
  }

  private applyTheme(mode: ThemeMode): void {
    const isDark =
      mode === 'dark' ||
      (mode === 'system' && this.mediaQuery?.matches === true);

    this._resolved.set(isDark ? 'dark' : 'light');

    if (typeof document !== 'undefined') {
      document.documentElement.classList.toggle('dark', isDark);
    }
  }
}
